@import "tailwindcss";
@import "tw-animate-css";
@import "shadcn/tailwind.css";

@custom-variant dark (&:is(.dark *));

@theme inline {
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --font-sans: var(--font-geist-sans);
  --font-mono: var(--font-geist-mono);
  --font-heading: var(--font-geist-sans);
  --color-sidebar-ring: var(--sidebar-ring);
  --color-sidebar-border: var(--sidebar-border);
  --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
  --color-sidebar-accent: var(--sidebar-accent);
  --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
  --color-sidebar-primary: var(--sidebar-primary);
  --color-sidebar-foreground: var(--sidebar-foreground);
  --color-sidebar: var(--sidebar);
  --color-chart-5: var(--chart-5);
  --color-chart-4: var(--chart-4);
  --color-chart-3: var(--chart-3);
  --color-chart-2: var(--chart-2);
  --color-chart-1: var(--chart-1);
  --color-ring: var(--ring);
  --color-input: var(--input);
  --color-border: var(--border);
  --color-destructive: var(--destructive);
  --color-accent-foreground: var(--accent-foreground);
  --color-accent: var(--accent);
  --color-muted-foreground: var(--muted-foreground);
  --color-muted: var(--muted);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-secondary: var(--secondary);
  --color-primary-foreground: var(--primary-foreground);
  --color-primary: var(--primary);
  --color-popover-foreground: var(--popover-foreground);
  --color-popover: var(--popover);
  --color-card-foreground: var(--card-foreground);
  --color-card: var(--card);
  --radius-sm: calc(var(--radius) * 0.6);
  --radius-md: calc(var(--radius) * 0.8);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) * 1.4);
  --radius-2xl: calc(var(--radius) * 1.8);
  --radius-3xl: calc(var(--radius) * 2.2);
  --radius-4xl: calc(var(--radius) * 2.6);

  /* Custom additions */
  --color-glow: var(--glow);
  --color-surface: var(--surface);
  --color-surface-hover: var(--surface-hover);
}

/* ═══════════════════════════════════════════
   LIGHT THEME — Clean, minimal, Vercel-like
   ═══════════════════════════════════════════ */
:root {
  --background: oklch(0.99 0 0);
  --foreground: oklch(0.13 0 0);
  --card: oklch(1 0 0);
  --card-foreground: oklch(0.13 0 0);
  --popover: oklch(1 0 0);
  --popover-foreground: oklch(0.13 0 0);
  --primary: oklch(0.13 0 0);
  --primary-foreground: oklch(0.99 0 0);
  --secondary: oklch(0.96 0 0);
  --secondary-foreground: oklch(0.13 0 0);
  --muted: oklch(0.96 0 0);
  --muted-foreground: oklch(0.45 0 0);
  --accent: oklch(0.96 0 0);
  --accent-foreground: oklch(0.13 0 0);
  --destructive: oklch(0.55 0.22 27);
  --border: oklch(0.91 0 0);
  --input: oklch(0.91 0 0);
  --ring: oklch(0.13 0 0);
  --radius: 0.5rem;
  --glow: oklch(0.7 0.15 250 / 0.15);
  --surface: oklch(0.97 0 0);
  --surface-hover: oklch(0.94 0 0);

  --chart-1: oklch(0.65 0.18 250);
  --chart-2: oklch(0.7 0.15 170);
  --chart-3: oklch(0.6 0.2 310);
  --chart-4: oklch(0.75 0.12 70);
  --chart-5: oklch(0.55 0.2 30);

  --sidebar: oklch(0.98 0 0);
  --sidebar-foreground: oklch(0.13 0 0);
  --sidebar-primary: oklch(0.13 0 0);
  --sidebar-primary-foreground: oklch(0.99 0 0);
  --sidebar-accent: oklch(0.96 0 0);
  --sidebar-accent-foreground: oklch(0.13 0 0);
  --sidebar-border: oklch(0.91 0 0);
  --sidebar-ring: oklch(0.13 0 0);
}

/* ═══════════════════════════════════════════
   DARK THEME — Cinematic, Linear-inspired
   ═══════════════════════════════════════════ */
.dark {
  --background: oklch(0.1 0 0);
  --foreground: oklch(0.93 0 0);
  --card: oklch(0.14 0 0);
  --card-foreground: oklch(0.93 0 0);
  --popover: oklch(0.14 0 0);
  --popover-foreground: oklch(0.93 0 0);
  --primary: oklch(0.93 0 0);
  --primary-foreground: oklch(0.1 0 0);
  --secondary: oklch(0.18 0 0);
  --secondary-foreground: oklch(0.93 0 0);
  --muted: oklch(0.18 0 0);
  --muted-foreground: oklch(0.55 0 0);
  --accent: oklch(0.18 0 0);
  --accent-foreground: oklch(0.93 0 0);
  --destructive: oklch(0.65 0.2 25);
  --border: oklch(1 0 0 / 8%);
  --input: oklch(1 0 0 / 10%);
  --ring: oklch(0.55 0 0);
  --glow: oklch(0.65 0.2 250 / 0.15);
  --surface: oklch(0.14 0 0);
  --surface-hover: oklch(0.18 0 0);

  --chart-1: oklch(0.7 0.18 250);
  --chart-2: oklch(0.7 0.15 170);
  --chart-3: oklch(0.65 0.2 310);
  --chart-4: oklch(0.75 0.12 70);
  --chart-5: oklch(0.6 0.2 30);

  --sidebar: oklch(0.12 0 0);
  --sidebar-foreground: oklch(0.93 0 0);
  --sidebar-primary: oklch(0.65 0.2 250);
  --sidebar-primary-foreground: oklch(0.93 0 0);
  --sidebar-accent: oklch(0.18 0 0);
  --sidebar-accent-foreground: oklch(0.93 0 0);
  --sidebar-border: oklch(1 0 0 / 8%);
  --sidebar-ring: oklch(0.55 0 0);
}

@layer base {
  * {
    @apply border-border outline-ring/50;
  }
  body {
    @apply bg-background text-foreground;
  }
  html {
    @apply font-sans;
  }
}

/* ═══════════════════════════════════════════
   CUSTOM UTILITIES
   ═══════════════════════════════════════════ */
@layer utilities {
  /* Gradient text — subtle fade, use sparingly */
  .text-gradient {
    @apply bg-clip-text text-transparent;
    background-image: linear-gradient(
      180deg,
      oklch(0.75 0 0) 0%,
      oklch(0.45 0 0) 100%
    );
  }

  /* Subtle glow effect */
  .glow {
    box-shadow:
      0 0 20px oklch(0.65 0.15 250 / 0.1),
      0 0 60px oklch(0.65 0.15 250 / 0.05);
  }

  /* Glass morphism surface */
  .glass {
    @apply bg-white/5 backdrop-blur-xl border border-white/10;
  }

  /* Gradient border trick */
  .gradient-border {
    position: relative;
  }
  .gradient-border::before {
    content: "";
    position: absolute;
    inset: 0;
    border-radius: inherit;
    padding: 1px;
    background: linear-gradient(
      135deg,
      oklch(1 0 0 / 0.15),
      oklch(1 0 0 / 0.02)
    );
    -webkit-mask:
      linear-gradient(#fff 0 0) content-box,
      linear-gradient(#fff 0 0);
    mask:
      linear-gradient(#fff 0 0) content-box,
      linear-gradient(#fff 0 0);
    -webkit-mask-composite: xor;
    mask-composite: exclude;
    pointer-events: none;
  }

  /* Noise texture overlay */
  .noise::after {
    content: "";
    position: absolute;
    inset: 0;
    background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)' opacity='0.03'/%3E%3C/svg%3E");
    pointer-events: none;
    border-radius: inherit;
  }
}
